THE RISK:
{
 "id": "som-window-semantics-mismatch",
 "title": "The 3% Year-1 obtainable is a 3–5-year benchmark wearing a 12-month clock",
 "narrative": "The obtainableFactor was 'triangulated' from generic SOM heuristics — but the benchmark sources themselves disagree on what period the percentage describes. Wise defines SOM as a 3–5-year capture window; Prospeo and IdeaPlan frame 1–3 years. Applied to a single pre-launch year, the same literature implies numbers an order of magnitude lower: TryBuildCo's own worked example lands at ~0.1% of SAM, and the one real industrial hardware entrant found (Tractian) started at ~$200K against a $14.9B market. The model's 0.01–0.05 band brackets the wrong quantity — it brackets a multi-year share, not a first-12-months share for a company that starts the year without certs, channel, or references.",
 "category": "model-structure",
 "targetNodes": [
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The benchmarks behind the 3% mid-band describe 1–3 or 3–5 year capture windows, not the first 12 months the profile specifies",
   "refs": [
    "digest:obtainable-benchmark#c1",
    "digest:obtainable-benchmark#c4",
    "profile:Stage"
   ]
  },
  {
   "step": "propagation",
   "text": "When the same sources are read at the Year-1 grain, observed and worked-example first-period shares fall to 0.1% of SAM and below — orders of magnitude under the curated band's 1% floor",
   "refs": [
    "digest:obtainable-benchmark#c5",
    "digest:obtainable-benchmark#c6",
    "digest:obtainable-benchmark#c7"
   ]
  },
  {
   "step": "model-impact",
   "text": "obtainableFactor 0.03 overstates Year-1 capture by roughly 5x; YAM scales linearly with it while TAM/SAM stay untouched",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "The node was already revised DOWN (from 6% to 3%) and is labelled 'triangulated' with two agreeing sources — it looks like the conservative, well-handled assumption. The flaw is not the number's level but the time-unit mismatch between the benchmark's window and the model's, which no sensitivity band expresses.",
 "expectedObviousness": "medium",
 "falsifier": "Any named DC-hardware or comparable industrial B2B entrant with a documented first-12-months revenue at or above 1% of its stated SAM in a market with incumbent CR3 near 0.55.",
 "likelihood": {
  "value": 0.6,
  "rationale": "Every source that quantifies a real first period (TryBuildCo example, Tractian) sits far below 1%, and the digests found zero sector-specific Year-1 benchmarks supporting 3%; countervailing: AI-driven demand growth may lift new-entrant win rates above historical analogues. [evidence revision: Four independent SOM definitions confirm the 3–5-year framing behind the benchmark, and the one comparable industrial-hardware entrant (Tractian) started far below 1% of SAM and took years to scale, strengthening both the trigger and propagation premises. No falsifying entrant surfaced. Raising from 0.45 to 0.60; not higher because the year-1 SAM-share magnitudes are inferred by triangulation rather than a direct sector-specific year-1 benchmark, and demand-growth/AI tailwinds remain an unquantified countervailing factor.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "obtainableFactor",
   "op": "set",
   "value": 0.006,
   "note": "Year-1 obtainable re-anchored on first-period analogues rather than multi-year SOM heuristics"
  }
 ],
 "indicators": [
  {
   "signal": "Months from launch to first paid PO for new rack-power/DC-hardware entrants in EMEA",
   "where": "Press releases and case studies of recent PDU/rack-power market entrants; Data Centre Dynamics vendor-launch coverage",
   "threshold": ">9 months median to first PO",
   "updates": "increases"
  },
  {
   "signal": "Time for a new vendor to appear on CE electrical-distributor line cards after launch",
   "where": "Rexel, Sonepar and regional CE distributor published line cards / new-vendor announcements",
   "threshold": ">2 quarters to first listing",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Replace the percentage heuristic with a capacity-based bottom-up model (named accounts × win rate × sales-cycle length × deployment capacity) before committing the Year-1 plan",
   "type": "information",
   "voiNodeId": "obtainableFactor",
   "note": "Prospeo itself recommends this over the percentage heuristic; the digests confirm no one has instantiated it for DC hardware"
  },
  {
   "action": "Structure Year-1 targets and cash plan around a 0.5–1% obtainable case, treating 3% as upside rather than base",
   "type": "operational",
   "voiNodeId": null,
   "note": "Prevents the ramp-dependent hiring and inventory commitments that make an overstated YAM fatal rather than embarrassing"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Calculating market size with TAM, SAM and SOM for startups",
   "sourceType": "industry-report",
   "publisher": "Wise",
   "date": "2026-01-21",
   "excerpt": "Serviceable Obtainable Market (SOM): The realistic share of SAM you expect to capture in the next three to five years, accounting for competition and your execution capacity.",
   "url": "https://wise.com/gb/blog/tam-sam-vs-som",
   "attached": true
  },
  {
   "title": "Tractian: How Two Sons of Factory Engineers Built a $32M Business",
   "sourceType": "triangulation",
   "publisher": "Solopreneur",
   "date": "2026-05-30",
   "excerpt": "The company grew from $200K to $32M in revenue over four years and serves more than 1,000 plants... Market $14.9 млрд.",
   "url": "https://solopreneuro.com/en/ideas/tractian-maintenance-ai",
   "attached": true
  },
  {
   "title": "What is SOM? | Angel Investors Network Glossary",
